//! # bowl-probe — the τ-bowl gate on REAL admitted-model weights.
//!
//! Converts the JIT-dequantization story from synthetic to real: load an
//! ADMITTED dense `.knot` (default: the 374 MB `qwen2.5-0.5b-instruct`, which
//! passes the monster-swarm qspec gate), pull a real weight matrix through the
//! *tested* loader dequant path, and run the cell-filling diagnostic + the
//! Tukey-bowl accept-rate (cubic vs E_8) + conformal admission on its real
//! tiles.
//!
//! HONESTY GATE: to avoid a format-misread producing garbage-but-plausible
//! numbers (the Sardis failure this whole project guards against), the probe
//! only analyses F16/F32/Q8_0 matrices (dequantized with the public/tested
//! loader paths or the crate's mirrored Q8_0 block layout) and ABORTS with a
//! diagnostic if the extracted weights fail a sanity check (non-finite,
//! implausible magnitude, or shape mismatch) — it never reports a number it
//! cannot trust.
//!
//! Usage:
//!   bowl-probe [--knot <path>] [--quality-profile dev-balanced]
//!              [--matrix-type any|float|q8_0] [--step <f>]
//!              [--step-divisor <f>] [--gamma-multiplier <f>]
//!              [--q-values 0.90,0.95,0.99] [--max-rows <n>]
//!              [--gamma-sweep 1.40:2.10:0.05]
//!              [--format text|json] [--output <report.json>]
//! Default knot: ~/.edgework/models/qwen2.5-0.5b-instruct.knot

use distributed_inference::conformal_gate::{conformal_admit, ResidualCalibration};
use distributed_inference::kv_cache_e8::{
    bowl_gate_report, characterize_kv_cell_filling, mean_sq_quant_error, KvCentering, KvQuantizer,
};
use distributed_inference::loader::KnotWeights;
use distributed_inference::model::{bytes_to_f32_slice, dequantize_f16_row};
use std::path::Path;

const DEFAULT_KNOT_NAME: &str = ".edgework/models/qwen2.5-0.5b-instruct.knot";

const PROOF_SPINE: &[(&str, &str)] = &[
    (
        "quality_margin_cache",
        "Gnosis.QualityMarginCacheAdmissibility",
    ),
    (
        "energy_margin_bridge",
        "Gnosis.EnergyMarginBridgeAdmissibility",
    ),
    ("basin_separatrix", "Gnosis.BasinSeparatrixAdmissibility"),
    ("jit_dequant_capstone", "Gnosis.JitDequantAdmissibility"),
    (
        "conformal_coverage",
        "Gnosis.ConformalCoverageAdmissibility",
    ),
];

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum QualityProfile {
    DevFast,
    DevBalanced,
    DevStrict,
}

impl QualityProfile {
    fn parse(raw: &str) -> Result<Self, String> {
        match raw {
            "dev-fast" | "fast" => Ok(Self::DevFast),
            "dev-balanced" | "balanced" => Ok(Self::DevBalanced),
            "dev-strict" | "strict" => Ok(Self::DevStrict),
            other => Err(format!(
                "--quality-profile expected dev-fast|dev-balanced|dev-strict, got {other:?}"
            )),
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::DevFast => "dev-fast",
            Self::DevBalanced => "dev-balanced",
            Self::DevStrict => "dev-strict",
        }
    }

    fn default_max_rows(self) -> usize {
        match self {
            Self::DevFast => 2048,
            Self::DevBalanced => 8000,
            Self::DevStrict => 16000,
        }
    }

    fn default_step_divisor(self) -> f64 {
        match self {
            Self::DevFast => 3.0,
            Self::DevBalanced => 4.0,
            Self::DevStrict => 6.0,
        }
    }

    fn default_gamma_multiplier(self) -> f64 {
        match self {
            Self::DevFast => 2.5,
            Self::DevBalanced => 2.0,
            Self::DevStrict => 1.5,
        }
    }

    fn default_q_values(self) -> Vec<f64> {
        match self {
            Self::DevFast => vec![0.90, 0.95],
            Self::DevBalanced => vec![0.90, 0.95, 0.99],
            Self::DevStrict => vec![0.95, 0.99],
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum MatrixType {
    Any,
    Float,
    Q8_0,
}

impl MatrixType {
    fn parse(raw: &str) -> Result<Self, String> {
        match raw {
            "any" => Ok(Self::Any),
            "float" | "f16f32" | "f16-f32" => Ok(Self::Float),
            "q8_0" | "q8" | "Q8_0" => Ok(Self::Q8_0),
            other => Err(format!(
                "--matrix-type expected any|float|q8_0, got {other:?}"
            )),
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::Any => "any",
            Self::Float => "float",
            Self::Q8_0 => "q8_0",
        }
    }

    fn allows(self, tensor_type: &str) -> bool {
        match self {
            Self::Any => is_q8_0(tensor_type) || is_f16(tensor_type) || is_f32(tensor_type),
            Self::Float => is_f16(tensor_type) || is_f32(tensor_type),
            Self::Q8_0 => is_q8_0(tensor_type),
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum OutputFormat {
    Text,
    Json,
}

impl OutputFormat {
    fn parse(raw: &str) -> Result<Self, String> {
        match raw {
            "text" => Ok(Self::Text),
            "json" => Ok(Self::Json),
            other => Err(format!("--format expected text|json, got {other:?}")),
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::Text => "text",
            Self::Json => "json",
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq)]
struct GammaSweep {
    start: f64,
    end: f64,
    step: f64,
}

impl GammaSweep {
    fn parse(raw: &str) -> Result<Self, String> {
        let parts = raw.split(':').collect::<Vec<_>>();
        if parts.len() != 3 {
            return Err(format!(
                "--gamma-sweep expected start:end:step, got {raw:?}"
            ));
        }
        let parse_part = |label: &str, value: &str| -> Result<f64, String> {
            let parsed = value
                .parse::<f64>()
                .map_err(|e| format!("bad --gamma-sweep {label} {value:?}: {e}"))?;
            if parsed <= 0.0 || !parsed.is_finite() {
                return Err(format!("--gamma-sweep {label} must be positive and finite"));
            }
            Ok(parsed)
        };
        let start = parse_part("start", parts[0])?;
        let end = parse_part("end", parts[1])?;
        let step = parse_part("step", parts[2])?;
        if end < start {
            return Err("--gamma-sweep end must be >= start".to_string());
        }
        let count = ((end - start) / step).floor() as usize + 1;
        if count > 256 {
            return Err("--gamma-sweep would emit more than 256 points".to_string());
        }
        Ok(Self { start, end, step })
    }

    fn multipliers(self) -> Vec<f64> {
        let mut out = Vec::new();
        let mut value = self.start;
        let epsilon = self.step.abs() * 1e-9;
        while value <= self.end + epsilon {
            out.push(value);
            value += self.step;
        }
        out
    }
}

#[derive(Clone, Debug)]
struct Args {
    knot: String,
    step: Option<f32>,
    max_rows: usize,
    quality_profile: QualityProfile,
    matrix_type: MatrixType,
    q_values: Vec<f64>,
    gamma_multiplier: f64,
    step_divisor: f64,
    gamma_sweep: Option<GammaSweep>,
    format: OutputFormat,
    output: Option<String>,
}

fn default_knot_path() -> String {
    format!(
        "{}/{}",
        std::env::var("HOME").unwrap_or_default(),
        DEFAULT_KNOT_NAME
    )
}

fn usage() {
    eprintln!(
        "usage: bowl-probe [--knot PATH] [--quality-profile dev-fast|dev-balanced|dev-strict] \
         [--matrix-type any|float|q8_0] [--step F] [--step-divisor F] \
         [--gamma-multiplier F] [--q-values 0.90,0.95,0.99] [--max-rows N] \
         [--gamma-sweep start:end:step] [--format text|json] [--json] [--output report.json]"
    );
}

fn parse_q_values(raw: &str) -> Result<Vec<f64>, String> {
    let mut values = Vec::new();
    for part in raw.split(',') {
        let trimmed = part.trim();
        if trimmed.is_empty() {
            continue;
        }
        let q = trimmed
            .parse::<f64>()
            .map_err(|e| format!("bad q value {trimmed:?}: {e}"))?;
        if q <= 0.0 || q >= 1.0 {
            return Err(format!("q value must be in (0, 1), got {q}"));
        }
        values.push(q);
    }
    if values.is_empty() {
        return Err("--q-values must contain at least one probability".to_string());
    }
    Ok(values)
}

fn split_eq(arg: &str) -> (String, Option<String>) {
    match arg.find('=') {
        Some(i) => (arg[..i].to_string(), Some(arg[i + 1..].to_string())),
        None => (arg.to_string(), None),
    }
}

fn parse_args_from(argv: &[String]) -> Result<Args, String> {
    let mut knot = default_knot_path();
    let mut step = None;
    let mut max_rows = None;
    let mut quality_profile = QualityProfile::DevBalanced;
    let mut matrix_type = MatrixType::Any;
    let mut q_values = None;
    let mut gamma_multiplier = None;
    let mut step_divisor = None;
    let mut gamma_sweep = None;
    let mut format = OutputFormat::Text;
    let mut output = None;

    let mut i = 1;
    while i < argv.len() {
        let (flag, inline_val) = split_eq(&argv[i]);
        let mut take_value = |name: &str| -> Result<String, String> {
            if let Some(v) = inline_val.clone() {
                Ok(v)
            } else {
                i += 1;
                argv.get(i)
                    .cloned()
                    .ok_or_else(|| format!("{name} needs a value"))
            }
        };

        match flag.as_str() {
            "--knot" => knot = take_value("--knot")?,
            "--step" => {
                let v = take_value("--step")?;
                let parsed = v
                    .parse::<f32>()
                    .map_err(|e| format!("bad --step {v:?}: {e}"))?;
                if parsed <= 0.0 || !parsed.is_finite() {
                    return Err("--step must be a positive finite number".to_string());
                }
                step = Some(parsed);
            }
            "--max-rows" => {
                let v = take_value("--max-rows")?;
                let parsed = v
                    .parse::<usize>()
                    .map_err(|e| format!("bad --max-rows {v:?}: {e}"))?;
                if parsed == 0 {
                    return Err("--max-rows must be > 0".to_string());
                }
                max_rows = Some(parsed);
            }
            "--quality-profile" => {
                let v = take_value("--quality-profile")?;
                quality_profile = QualityProfile::parse(&v)?;
            }
            "--matrix-type" => {
                let v = take_value("--matrix-type")?;
                matrix_type = MatrixType::parse(&v)?;
            }
            "--q-values" => {
                let v = take_value("--q-values")?;
                q_values = Some(parse_q_values(&v)?);
            }
            "--gamma-multiplier" => {
                let v = take_value("--gamma-multiplier")?;
                let parsed = v
                    .parse::<f64>()
                    .map_err(|e| format!("bad --gamma-multiplier {v:?}: {e}"))?;
                if parsed <= 0.0 || !parsed.is_finite() {
                    return Err("--gamma-multiplier must be positive and finite".to_string());
                }
                gamma_multiplier = Some(parsed);
            }
            "--gamma-sweep" => {
                let v = take_value("--gamma-sweep")?;
                gamma_sweep = Some(GammaSweep::parse(&v)?);
            }
            "--step-divisor" => {
                let v = take_value("--step-divisor")?;
                let parsed = v
                    .parse::<f64>()
                    .map_err(|e| format!("bad --step-divisor {v:?}: {e}"))?;
                if parsed <= 0.0 || !parsed.is_finite() {
                    return Err("--step-divisor must be positive and finite".to_string());
                }
                step_divisor = Some(parsed);
            }
            "--format" => {
                let v = take_value("--format")?;
                format = OutputFormat::parse(&v)?;
            }
            "--json" => format = OutputFormat::Json,
            "--output" => output = Some(take_value("--output")?),
            "-h" | "--help" => {
                usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {other}")),
        }
        i += 1;
    }

    Ok(Args {
        knot,
        step,
        max_rows: max_rows.unwrap_or_else(|| quality_profile.default_max_rows()),
        quality_profile,
        matrix_type,
        q_values: q_values.unwrap_or_else(|| quality_profile.default_q_values()),
        gamma_multiplier: gamma_multiplier
            .unwrap_or_else(|| quality_profile.default_gamma_multiplier()),
        step_divisor: step_divisor.unwrap_or_else(|| quality_profile.default_step_divisor()),
        gamma_sweep,
        format,
        output,
    })
}

fn write_report(path: &str, report: &serde_json::Value) -> Result<(), String> {
    let path = Path::new(path);
    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() {
            std::fs::create_dir_all(parent)
                .map_err(|e| format!("create {}: {e}", parent.display()))?;
        }
    }
    let bytes = serde_json::to_vec_pretty(report).map_err(|e| format!("serialize report: {e}"))?;
    std::fs::write(path, [bytes.as_slice(), b"\n"].concat())
        .map_err(|e| format!("write {}: {e}", path.display()))
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = std::env::args().collect();
    parse_args_from(&argv)
}

fn is_f16(t: &str) -> bool {
    matches!(t, "f16" | "F16" | "fp16" | "FP16" | "half")
}
fn is_f32(t: &str) -> bool {
    matches!(t, "f32" | "F32" | "fp32" | "FP32")
}
fn is_q8_0(t: &str) -> bool {
    matches!(t, "Q8_0" | "q8_0")
}

/// Standard IEEE-754 half → f32 (for the Q8_0 per-block scale).
fn f16_to_f32(h: u16) -> f32 {
    let sign = (h >> 15) & 1;
    let exp = (h >> 10) & 0x1f;
    let mant = h & 0x3ff;
    let val = if exp == 0 {
        // subnormal
        (mant as f32) * 2f32.powi(-24)
    } else if exp == 0x1f {
        if mant == 0 {
            f32::INFINITY
        } else {
            f32::NAN
        }
    } else {
        (1.0 + mant as f32 / 1024.0) * 2f32.powi(exp as i32 - 15)
    };
    if sign == 1 {
        -val
    } else {
        val
    }
}

/// Q8_0 row dequant — VERBATIM the crate's tested `mat_vec_q8_0_reference` block
/// layout (model.rs): `ceil(cols/32)` blocks of 34 bytes = `[2-byte f16 scale]
/// [32 × i8]`, value = `i8 × scale`. Mirrored (not invented) so it can't
/// misread the format; the caller's sanity gate is the backstop.
fn dequantize_q8_0_row(out: &mut [f32], w: &[u8], row: usize, cols: usize) {
    let blocks_per_row = cols.div_ceil(32);
    let row_start = row * blocks_per_row * 34;
    for block in 0..blocks_per_row {
        let bs = row_start + block * 34;
        let scale = f16_to_f32(u16::from_le_bytes([w[bs], w[bs + 1]]));
        let xo = block * 32;
        for j in 0..32 {
            let idx = xo + j;
            if idx < cols {
                out[idx] = (w[bs + 2 + j] as i8) as f32 * scale;
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn argv(args: &[&str]) -> Vec<String> {
        std::iter::once("bowl-probe".to_string())
            .chain(args.iter().map(|s| s.to_string()))
            .collect()
    }

    #[test]
    fn balanced_profile_supplies_operational_defaults() {
        let args = parse_args_from(&argv(&[])).unwrap();
        assert_eq!(args.quality_profile, QualityProfile::DevBalanced);
        assert_eq!(args.max_rows, 8000);
        assert_eq!(args.step_divisor, 4.0);
        assert_eq!(args.gamma_multiplier, 2.0);
        assert_eq!(args.q_values, vec![0.90, 0.95, 0.99]);
        assert_eq!(args.matrix_type, MatrixType::Any);
        assert_eq!(args.format, OutputFormat::Text);
    }

    #[test]
    fn strict_profile_can_be_overridden_for_admission_sweeps() {
        let args = parse_args_from(&argv(&[
            "--quality-profile=dev-strict",
            "--matrix-type=q8_0",
            "--max-rows",
            "123",
            "--q-values",
            "0.8,0.99",
            "--gamma-multiplier",
            "1.25",
            "--step-divisor",
            "7.5",
            "--gamma-sweep",
            "1.4:2.0:0.2",
            "--format",
            "json",
            "--output",
            "/tmp/bowl-probe.json",
        ]))
        .unwrap();
        assert_eq!(args.quality_profile, QualityProfile::DevStrict);
        assert_eq!(args.matrix_type, MatrixType::Q8_0);
        assert_eq!(args.max_rows, 123);
        assert_eq!(args.q_values, vec![0.8, 0.99]);
        assert_eq!(args.gamma_multiplier, 1.25);
        assert_eq!(args.step_divisor, 7.5);
        assert_eq!(
            args.gamma_sweep,
            Some(GammaSweep {
                start: 1.4,
                end: 2.0,
                step: 0.2
            })
        );
        assert_eq!(args.format, OutputFormat::Json);
        assert_eq!(args.output.as_deref(), Some("/tmp/bowl-probe.json"));
    }

    #[test]
    fn gamma_sweep_expands_grid_without_overrun() {
        let sweep = GammaSweep::parse("1.4:1.8:0.2").unwrap();
        let values = sweep.multipliers();
        assert_eq!(values.len(), 3);
        assert!((values[0] - 1.4).abs() < 1e-12);
        assert!((values[1] - 1.6).abs() < 1e-12);
        assert!((values[2] - 1.8).abs() < 1e-12);
        assert!(GammaSweep::parse("2.0:1.0:0.1").is_err());
        assert!(GammaSweep::parse("1.0:100.0:0.01").is_err());
    }

    #[test]
    fn q8_0_row_dequant_matches_block_layout() {
        let mut row_bytes = vec![0u8; 34];
        row_bytes[0] = 0x00;
        row_bytes[1] = 0x38; // f16 0.5
        row_bytes[2] = 1u8;
        row_bytes[3] = (-2i8) as u8;
        row_bytes[4] = 7u8;

        let mut out = vec![0.0; 3];
        dequantize_q8_0_row(&mut out, &row_bytes, 0, 3);
        assert_eq!(out, vec![0.5, -1.0, 3.5]);
    }

    #[test]
    fn q_values_reject_non_probabilities() {
        assert!(parse_q_values("0.95,1.0").is_err());
        assert!(parse_q_values("0.0").is_err());
        assert!(parse_q_values("").is_err());
    }
}

fn main() {
    let args = match parse_args() {
        Ok(args) => args,
        Err(e) => {
            usage();
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    };

    eprintln!("[bowl-probe] loading dense knot: {}", args.knot);
    eprintln!(
        "[bowl-probe] quality={} matrix-type={} max-rows={} step={} step-divisor={:.3} gamma-multiplier={:.3} q-values={:?} format={}",
        args.quality_profile.as_str(),
        args.matrix_type.as_str(),
        args.max_rows,
        args.step
            .map(|s| format!("{s:.6}"))
            .unwrap_or_else(|| "auto".to_string()),
        args.step_divisor,
        args.gamma_multiplier,
        args.q_values,
        args.format.as_str()
    );
    let kw = KnotWeights::load(&args.knot).unwrap_or_else(|e| {
        eprintln!("FATAL: load failed: {e}");
        std::process::exit(2);
    });

    // Choose a real weight matrix to analyse. Prefer the token embedding (the
    // largest real matrix; Q8_0 in qwen2.5-0.5b) sized from the knot config;
    // fall back to the largest shaped 2-D F16/F32/Q8_0 tensor. Q8_0/F16/F32 are
    // the formats we can dequantize via tested/mirrored paths without misreading.
    let (cfg_vocab, cfg_hidden) = kw
        .config
        .as_ref()
        .map(|c| (c.vocab_size, c.hidden_dim))
        .unwrap_or((0, 0));
    let mut inventory: Vec<(String, String, usize)> = kw
        .metadata
        .iter()
        .map(|(n, info)| (n.clone(), info.tensor_type.clone(), info.length as usize))
        .collect();
    let pick: Option<(String, usize, usize, String)> = {
        let embed = kw.metadata.get("token_embd_weight").and_then(|info| {
            let t = info.tensor_type.clone();
            if args.matrix_type.allows(&t) && cfg_vocab >= 64 && cfg_hidden >= 64 {
                Some(("token_embd_weight".to_string(), cfg_vocab, cfg_hidden, t))
            } else {
                None
            }
        });
        embed.or_else(|| {
            let mut best: Option<(String, usize, usize, String)> = None;
            for (name, info) in kw.metadata.iter() {
                let t = &info.tensor_type;
                if !args.matrix_type.allows(t) {
                    continue;
                }
                if let Some(shape) = &info.shape {
                    if shape.len() == 2 && shape[0] >= 64 && shape[1] >= 64 {
                        let (r, c) = (shape[0], shape[1]);
                        if best.as_ref().map(|b| r * c > b.1 * b.2).unwrap_or(true) {
                            best = Some((name.clone(), r, c, t.clone()));
                        }
                    }
                }
            }
            best
        })
    };

    let (name, rows, cols, kind) = match pick {
        Some(p) => p,
        None => {
            eprintln!(
                "[bowl-probe] no dequantable matrix found for matrix-type={}. Inventory (top 20):",
                args.matrix_type.as_str()
            );
            inventory.sort_by_key(|x| std::cmp::Reverse(x.2));
            for (n, t, len) in inventory.iter().take(20) {
                eprintln!("    {t:<8} {len:>12}  {n}");
            }
            eprintln!("=> would need a supported matrix type or a new row-dequant. Aborting (no fake numbers).");
            std::process::exit(3);
        }
    };

    eprintln!("[bowl-probe] chosen REAL weight matrix: {name}  [{rows} x {cols}]  type={kind}");

    let bytes = kw.backend.fetch_tensor(&name).unwrap_or_else(|e| {
        eprintln!("FATAL: fetch_tensor failed: {e}");
        std::process::exit(2);
    });
    let raw: &[u8] = bytes.as_ref();

    // Length sanity vs the format's expected byte count (catches wrong dims).
    let expect = if is_q8_0(&kind) {
        rows * cols.div_ceil(32) * 34
    } else if is_f16(&kind) {
        rows * cols * 2
    } else {
        rows * cols * 4
    };
    if raw.len() < expect {
        eprintln!(
            "FATAL: tensor bytes {} < expected {} for {kind} [{rows}x{cols}]",
            raw.len(),
            expect
        );
        std::process::exit(2);
    }

    // Dequantize to f32 rows (tested / verbatim-mirrored paths only).
    let n_rows = rows.min(args.max_rows);
    if n_rows < 4 {
        eprintln!(
            "FATAL: need at least 4 sampled rows for train/test conformal split, got {n_rows}"
        );
        std::process::exit(2);
    }
    let mut tiles: Vec<Vec<f32>> = Vec::with_capacity(n_rows);
    let mut row = vec![0.0f32; cols];
    let flat = if is_f32(&kind) {
        Some(bytes_to_f32_slice(raw))
    } else {
        None
    };
    for i in 0..n_rows {
        if is_q8_0(&kind) {
            dequantize_q8_0_row(&mut row, raw, i, cols);
        } else if is_f16(&kind) {
            dequantize_f16_row(&mut row, raw, i, cols);
        } else {
            row.copy_from_slice(&flat.as_ref().unwrap()[i * cols..(i + 1) * cols]);
        }
        tiles.push(row.clone());
    }

    // ── HONESTY / SANITY GATE: refuse to report on garbage ──
    let mut finite = true;
    let mut max_abs = 0.0f32;
    let mut sumsq = 0.0f64;
    let mut count = 0usize;
    for t in &tiles {
        for &v in t {
            if !v.is_finite() {
                finite = false;
            }
            max_abs = max_abs.max(v.abs());
            sumsq += v as f64 * v as f64;
            count += 1;
        }
    }
    let std = (sumsq / count.max(1) as f64).sqrt();
    if !finite || !(1e-6..=100.0).contains(&max_abs) || !(1e-7..=10.0).contains(&std) {
        eprintln!(
            "ABORT (sanity gate): finite={finite} max_abs={max_abs:.4} std={std:.5} — \
             extracted weights look wrong; refusing to report numbers."
        );
        std::process::exit(4);
    }
    eprintln!("[bowl-probe] sanity OK: {n_rows} real rows, std={std:.5}, max|w|={max_abs:.4}");

    let (step, step_source) = match args.step {
        Some(step) => (step, "explicit"),
        None => (
            (std as f32 / args.step_divisor as f32).max(1e-4),
            "auto-std-divisor",
        ),
    };

    // ── 1. Cell-filling on REAL weights ──
    let report = characterize_kv_cell_filling(&tiles, step);

    // ── 2. cubic vs E8 quant error + bowl accept-rate on REAL tiles ──
    let mse_cubic =
        mean_sq_quant_error(&tiles, KvQuantizer::Cubic, KvCentering::PerVectorMean, step);
    let mse_e8 = mean_sq_quant_error(
        &tiles,
        KvQuantizer::E8Tail,
        KvCentering::PerVectorMean,
        step,
    );
    let e8_vs_cubic_pct = if mse_cubic > 0.0 {
        (1.0 - mse_e8 / mse_cubic) * 100.0
    } else {
        f64::NAN
    };
    // L2 energy gate accept-rate at a margin set to ~2x the cubic L2 residual scale.
    let l2_scale = (mse_cubic.sqrt()) * (cols as f64).sqrt();
    let gamma = args.gamma_multiplier * l2_scale;
    let rc = bowl_gate_report(&tiles, KvQuantizer::Cubic, step, gamma);
    let re = bowl_gate_report(&tiles, KvQuantizer::E8Tail, step, gamma);

    // ── 3. conformal admission on REAL residuals (train/test split of rows) ──
    let split = n_rows * 7 / 10;
    let resid = |q: KvQuantizer, lo: usize, hi: usize| -> Vec<f64> {
        let mut out = vec![0.0f32; cols];
        let mut v = Vec::new();
        for t in &tiles[lo..hi] {
            distributed_inference::kv_cache_e8::quantize_kv_into(
                t,
                &mut out,
                &distributed_inference::kv_cache_e8::KvQuantConfig {
                    quantizer: q,
                    centering: KvCentering::PerVectorMean,
                    step,
                },
            );
            let mut s = 0.0f64;
            for j in 0..cols {
                let e = (t[j] - out[j]) as f64;
                s += e * e;
            }
            v.push(s.sqrt());
        }
        v
    };
    let cal = ResidualCalibration::from_residuals(&resid(KvQuantizer::E8Tail, 0, split));
    let test = resid(KvQuantizer::E8Tail, split, n_rows);
    let mut conformal_rows = Vec::new();
    for &q in &args.q_values {
        let tq = cal.conformal_quantile(q);
        let lie = if test.is_empty() {
            f64::NAN
        } else {
            test.iter().filter(|&&x| x > tq).count() as f64 / test.len() as f64
        };
        let adm = conformal_admit(&cal, q, gamma);
        conformal_rows.push((q, tq, lie, adm.admissible, adm.certified_lie_rate_le));
    }

    let proof_spine = PROOF_SPINE
        .iter()
        .map(|(key, module)| serde_json::json!({ "key": key, "module": module }))
        .collect::<Vec<_>>();
    let conformal = conformal_rows
        .iter()
        .map(
            |(q, threshold, realized_lie_rate, admissible, certified_lie_rate_le)| {
                serde_json::json!({
                    "q": q,
                    "threshold_l2": threshold,
                    "realized_lie_rate": realized_lie_rate,
                    "target_lie_rate": 1.0 - q,
                    "certified_lie_rate_le": certified_lie_rate_le,
                    "admit_at_gamma": admissible,
                })
            },
        )
        .collect::<Vec<_>>();
    let all_conformal_admit = conformal_rows
        .iter()
        .all(|(_, _, _, admissible, _)| *admissible);
    let e8_wins_mse = mse_cubic.is_finite() && mse_e8.is_finite() && mse_e8 <= mse_cubic;
    let e8_not_worse_energy = re.accept_rate_l2.is_finite()
        && rc.accept_rate_l2.is_finite()
        && re.accept_rate_l2 >= rc.accept_rate_l2;
    let admitted = finite
        && report.is_cell_filling
        && e8_wins_mse
        && e8_not_worse_energy
        && all_conformal_admit;
    let exact_conformal_min_multiplier = if l2_scale > 0.0 && l2_scale.is_finite() {
        conformal_rows
            .iter()
            .map(|(_, threshold, _, _, _)| 2.0 * *threshold / l2_scale)
            .fold(0.0f64, f64::max)
    } else {
        f64::NAN
    };
    let gamma_frontier = args.gamma_sweep.map(|sweep| {
        let mut first_admitted_multiplier = None;
        let mut last_rejected_multiplier = None;
        let rows = sweep
            .multipliers()
            .into_iter()
            .map(|multiplier| {
                let gamma_at_multiplier = multiplier * l2_scale;
                let rc_at =
                    bowl_gate_report(&tiles, KvQuantizer::Cubic, step, gamma_at_multiplier);
                let re_at =
                    bowl_gate_report(&tiles, KvQuantizer::E8Tail, step, gamma_at_multiplier);
                let e8_energy_accept_ge_cubic = re_at.accept_rate_l2.is_finite()
                    && rc_at.accept_rate_l2.is_finite()
                    && re_at.accept_rate_l2 >= rc_at.accept_rate_l2;
                let conformal_checks = conformal_rows
                    .iter()
                    .map(|(q, threshold, realized_lie_rate, _, certified_lie_rate_le)| {
                        let admission = conformal_admit(&cal, *q, gamma_at_multiplier);
                        serde_json::json!({
                            "q": q,
                            "threshold_l2": threshold,
                            "required_multiplier": if l2_scale > 0.0 { 2.0 * *threshold / l2_scale } else { f64::NAN },
                            "realized_lie_rate": realized_lie_rate,
                            "certified_lie_rate_le": certified_lie_rate_le,
                            "admit_at_gamma": admission.admissible,
                        })
                    })
                    .collect::<Vec<_>>();
                let all_conformal_admit_at = conformal_rows.iter().all(|(q, _, _, _, _)| {
                    conformal_admit(&cal, *q, gamma_at_multiplier).admissible
                });
                let admitted_at = finite
                    && report.is_cell_filling
                    && e8_wins_mse
                    && e8_energy_accept_ge_cubic
                    && all_conformal_admit_at;
                if admitted_at && first_admitted_multiplier.is_none() {
                    first_admitted_multiplier = Some(multiplier);
                }
                if !admitted_at {
                    last_rejected_multiplier = Some(multiplier);
                }
                serde_json::json!({
                    "multiplier": multiplier,
                    "gamma": gamma_at_multiplier,
                    "admitted": admitted_at,
                    "e8_energy_accept_ge_cubic": e8_energy_accept_ge_cubic,
                    "all_conformal_admit": all_conformal_admit_at,
                    "cubic_accept_rate_l2": rc_at.accept_rate_l2,
                    "e8_accept_rate_l2": re_at.accept_rate_l2,
                    "conformal": conformal_checks,
                })
            })
            .collect::<Vec<_>>();
        serde_json::json!({
            "sweep": {
                "start": sweep.start,
                "end": sweep.end,
                "step": sweep.step,
            },
            "exact_conformal_min_multiplier": exact_conformal_min_multiplier,
            "first_admitted_multiplier": first_admitted_multiplier,
            "last_rejected_multiplier": last_rejected_multiplier,
            "rows": rows,
        })
    });
    let output = serde_json::json!({
        "tool": "bowl-probe",
        "scope": "real admitted-model weights; no synthetic data",
        "knot": args.knot,
        "quality_profile": args.quality_profile.as_str(),
        "matrix_type_policy": args.matrix_type.as_str(),
        "admission": {
            "admitted": admitted,
            "policy": "finite && cell_filling && e8_mse_le_cubic && e8_energy_accept_ge_cubic && all_conformal_admit",
            "finite": finite,
            "cell_filling": report.is_cell_filling,
            "e8_mse_le_cubic": e8_wins_mse,
            "e8_energy_accept_ge_cubic": e8_not_worse_energy,
            "all_conformal_admit": all_conformal_admit,
        },
        "matrix": {
            "name": name,
            "rows": rows,
            "cols": cols,
            "sample_rows": n_rows,
            "tensor_type": kind,
        },
        "step": {
            "value": step,
            "source": step_source,
            "auto_divisor": args.step_divisor,
        },
        "gamma": {
            "value": gamma,
            "multiplier": args.gamma_multiplier,
            "cubic_l2_residual_scale": l2_scale,
            "exact_conformal_min_multiplier": exact_conformal_min_multiplier,
        },
        "sanity": {
            "finite": finite,
            "std": std,
            "max_abs": max_abs,
        },
        "cell_filling": {
            "effective_dim": report.effective_dim,
            "dim": report.dim,
            "mean_abs_corr": report.mean_abs_corr,
            "spread_in_cells": report.spread_in_cells,
            "is_cell_filling": report.is_cell_filling,
        },
        "quant_mse": {
            "cubic": mse_cubic,
            "e8_tail": mse_e8,
            "e8_vs_cubic_pct": e8_vs_cubic_pct,
        },
        "energy_gate": {
            "cubic_accept_rate_l2": rc.accept_rate_l2,
            "e8_accept_rate_l2": re.accept_rate_l2,
            "cubic_mean_tau_l2": rc.mean_tau_l2,
            "e8_mean_tau_l2": re.mean_tau_l2,
        },
        "conformal": {
            "train_rows": split,
            "test_rows": n_rows - split,
            "rows": conformal,
        },
        "proof_spine": proof_spine,
        "gamma_frontier": gamma_frontier,
    });
    if let Some(path) = &args.output {
        write_report(path, &output).unwrap_or_else(|e| {
            eprintln!("FATAL: report write failed: {e}");
            std::process::exit(2);
        });
        eprintln!("[bowl-probe] wrote report: {path}");
    }

    if args.format == OutputFormat::Json {
        println!("{}", serde_json::to_string_pretty(&output).unwrap());
    } else {
        println!("\n[REAL WEIGHTS | {name} {rows}x{cols} | step={step:.5} ({step_source})]");
        println!(
            "  quality: profile={} matrix-type={} sampled-rows={} gamma-multiplier={:.3}",
            args.quality_profile.as_str(),
            args.matrix_type.as_str(),
            n_rows,
            args.gamma_multiplier
        );
        println!(
            "  admission: {} (finite={finite} cell_filling={} e8_mse_le_cubic={} e8_energy_accept_ge_cubic={} all_conformal_admit={})",
            if admitted { "ADMIT" } else { "REJECT" },
            report.is_cell_filling,
            e8_wins_mse,
            e8_not_worse_energy,
            all_conformal_admit
        );
        println!(
            "  cert spine: {}",
            PROOF_SPINE
                .iter()
                .map(|(_, module)| *module)
                .collect::<Vec<_>>()
                .join(", ")
        );
        println!(
            "  cell-filling: effective_dim={:.1}/{} mean|corr|={:.3} spread_in_cells={:.2} => {}",
            report.effective_dim,
            report.dim,
            report.mean_abs_corr,
            report.spread_in_cells,
            if report.is_cell_filling {
                "CELL-FILLING (E8 should bite)"
            } else {
                "not cell-filling"
            }
        );
        println!(
            "  quant MSE: cubic={mse_cubic:.6}  E8Tail={mse_e8:.6}  ({e8_vs_cubic_pct:+.1}% vs cubic)"
        );
        println!(
            "  energy-gate accept @γ={gamma:.4}: cubic={:.1}%  E8={:.1}%  (mean τ₂ cubic={:.5} e8={:.5})",
            100.0 * rc.accept_rate_l2,
            100.0 * re.accept_rate_l2,
            rc.mean_tau_l2,
            re.mean_tau_l2
        );
        println!(
            "  conformal (E8 residuals, real weights, train {} -> test {}):",
            split,
            n_rows - split
        );
        for (q, tq, lie, admissible, _) in &conformal_rows {
            println!(
                "    q={q:.2}  Q_q={tq:.5}  realized-lie={:.2}% (target {:.0}%)  admit@gamma={}",
                100.0 * lie,
                100.0 * (1.0 - q),
                admissible
            );
        }
        println!("[bowl-probe] done — REAL admitted-model weights, no synthetic data.");
    }
}
